        if depth > 0 and rng.random() < 0.45:
            ops.append('pop'); args.append([]); depth -= 1
        elif rng.random() < 0.5:
            ops.append('push'); args.append([rng.randint(-1000, 1000)]); depth += 1
        elif depth > 0:
            choice = rng.choice(['top', 'getMin'])
            ops.append(choice); args.append([])
        else:
            ops.append('push'); args.append([rng.randint(-1000, 1000)]); depth += 1
    return [ops, args]

