class MinStack:
    def __init__(self):
        self.s = []
        self.m = []
    def push(self, value):
        self.s.append(value)
        self.m.append(value if not self.m else min(value, self.m[-1]))
    def pop(self):
        self.s.pop()
        self.m.pop()
    def top(self):
        return self.s[-1]
    def getMin(self):
        return self.m[-1]

