class MinStack {
    constructor() {
        this.s = [];
        this.m = [];
    }
    push(value) {
        this.s.push(value);
        this.m.push(this.m.length === 0 ? value : Math.min(value, this.m[this.m.length - 1]));
    }
    pop() {
        this.s.pop();
        this.m.pop();
    }
    top() {
        return this.s[this.s.length - 1];
    }
    getMin() {
        return this.m[this.m.length - 1];
    }
}
